1	import type { Element, XY } from '@bim-ai/core';
2	
3	export interface IfcExportOptions {
4	  includeStructure?: boolean;
5	  coordinateSystem?: 'local' | 'wgs84';
6	}
7	
8	// ---------------------------------------------------------------------------
9	// IFC entity ID counter
10	// ---------------------------------------------------------------------------
11	
12	class IdCounter {
13	  private n = 0;
14	  next(): number {
15	    return ++this.n;
16	  }
17	  current(): number {
18	    return this.n;
19	  }
20	}
21	
22	// ---------------------------------------------------------------------------
23	// Formatting helpers
24	// ---------------------------------------------------------------------------
25	
26	function guid(): string {
27	  // Produces a pseudo-random IFC GUID-style string (22 chars, base64url-ish).
28	  // IFC GUIDs are 22-character strings using a custom base64 alphabet.
29	  const alphabet = 'REDACTED$';
30	  let result = '';
31	  for (let i = 0; i < 22; i++) {
32	    result += alphabet[Math.floor(Math.random() * 64)];
33	  }
34	  return result;
35	}
36	
37	function ifcStr(s: string | null | undefined): string {
38	  if (s == null) return '$';
39	  return `'${s.replace(/'/g, "''")}'`;
40	}
41	
42	function ifcRef(id: number): string {
43	  return `#${id}`;
44	}
45	
46	function ifcRefList(ids: number[]): string {
47	  return `(${ids.map(ifcRef).join(',')})`;
48	}
49	
50	function mm2m(mm: number): number {
51	  return mm / 1000;
52	}
53	
54	// ---------------------------------------------------------------------------
55	// Geometry helpers
56	// ---------------------------------------------------------------------------
57	
58	function wallLength(start: XY, end: XY): number {
59	  const dx = end.xMm - start.xMm;
60	  const dy = end.yMm - start.yMm;
61	  return Math.sqrt(dx * dx + dy * dy);
62	}
63	
64	function wallAngleDeg(start: XY, end: XY): number {
65	  const dx = end.xMm - start.xMm;
66	  const dy = end.yMm - start.yMm;
67	  return (Math.atan2(dy, dx) * 180) / Math.PI;
68	}
69	
70	// ---------------------------------------------------------------------------
71	// Low-level entity emitters
72	// ---------------------------------------------------------------------------
73	
74	interface Lines {
75	  push(line: string): void;
76	}
77	
78	function emitCartesianPoint(
79	  lines: Lines,
80	  ids: IdCounter,
81	  x: number,
82	  y: number,
83	  z?: number,
84	): number {
85	  const id = ids.next();
86	  if (z !== undefined) {
87	    lines.push(`#${id}=IFCCARTESIANPOINT((${x.toFixed(6)},${y.toFixed(6)},${z.toFixed(6)}));`);
88	  } else {
89	    lines.push(`#${id}=IFCCARTESIANPOINT((${x.toFixed(6)},${y.toFixed(6)}));`);
90	  }
91	  return id;
92	}
93	
94	function emitDirection(lines: Lines, ids: IdCounter, x: number, y: number, z?: number): number {
95	  const id = ids.next();
96	  if (z !== undefined) {
97	    lines.push(`#${id}=IFCDIRECTION((${x.toFixed(6)},${y.toFixed(6)},${z.toFixed(6)}));`);
98	  } else {
99	    lines.push(`#${id}=IFCDIRECTION((${x.toFixed(6)},${y.toFixed(6)}));`);
100	  }
101	  return id;
102	}
103	
104	function emitAxis2Placement3D(
105	  lines: Lines,
106	  ids: IdCounter,
107	  origin: number,
108	  axis?: number,
109	  refDir?: number,
110	): number {
111	  const id = ids.next();
112	  const axisStr = axis != null ? ifcRef(axis) : '$';
113	  const refStr = refDir != null ? ifcRef(refDir) : '$';
114	  lines.push(`#${id}=IFCAXIS2PLACEMENT3D(${ifcRef(origin)},${axisStr},${refStr});`);
115	  return id;
116	}
117	
118	function emitLocalPlacement(
119	  lines: Lines,
120	  ids: IdCounter,
121	  placementRelTo: number | null,
122	  placement: number,
123	): number {
124	  const id = ids.next();
125	  const relStr = placementRelTo != null ? ifcRef(placementRelTo) : '$';
126	  lines.push(`#${id}=IFCLOCALPLACEMENT(${relStr},${ifcRef(placement)});`);
127	  return id;
128	}
129	
130	function emitShapeRepresentation(
131	  lines: Lines,
132	  ids: IdCounter,
133	  contextId: number,
134	  identifier: string,
135	  type: string,
136	  itemIds: number[],
137	): number {
138	  const id = ids.next();
139	  lines.push(
140	    `#${id}=IFCSHAPEREPRESENTATION(${ifcRef(contextId)},${ifcStr(identifier)},${ifcStr(type)},${ifcRefList(itemIds)});`,
141	  );
142	  return id;
143	}
144	
145	function emitProductDefinitionShape(lines: Lines, ids: IdCounter, repIds: number[]): number {
146	  const id = ids.next();
147	  lines.push(`#${id}=IFCPRODUCTDEFINITIONSHAPE($,$,${ifcRefList(repIds)});`);
148	  return id;
149	}
150	
151	// ---------------------------------------------------------------------------
152	// Wall geometry: IFCEXTRUDEDAREASOLID
153	// ---------------------------------------------------------------------------
154	
155	function emitWallBody(
156	  lines: Lines,
157	  ids: IdCounter,
158	  contextId: number,
159	  lengthMm: number,
160	  thicknessMm: number,
161	  heightMm: number,
162	): { shapeRepId: number; placementId: number } {
163	  // Profile: rectangle in local XZ (length × thickness)
164	  const profileOriginId = emitCartesianPoint(lines, ids, 0, 0);
165	  const profileXDirId = emitDirection(lines, ids, 1, 0);
166	  const profileYDirId = emitDirection(lines, ids, 0, 1);
167	  const profileAxisId = ids.next();
168	  lines.push(
169	    `#${profileAxisId}=IFCAXIS2PLACEMENT2D(${ifcRef(profileOriginId)},${ifcRef(profileXDirId)});`,
170	  );
171	  const profileId = ids.next();
172	  lines.push(
173	    `#${profileId}=IFCRECTANGLEPROFILEDEF(.AREA.,$,${ifcRef(profileAxisId)},${mm2m(lengthMm).toFixed(6)},${mm2m(thicknessMm).toFixed(6)});`,
174	  );
175	
176	  // Extrusion placement (origin at wall base start)
177	  const extrusionOriginId = emitCartesianPoint(lines, ids, 0, 0, 0);
178	  const extrusionAxisId = emitDirection(lines, ids, 0, 0, 1);
179	  const extrusionRefId = emitDirection(lines, ids, 1, 0, 0);
180	  const extrusionPlacementId = emitAxis2Placement3D(
181	    lines,
182	    ids,
183	    extrusionOriginId,
184	    extrusionAxisId,
185	    extrusionRefId,
186	  );
187	  const extrusionDirId = emitDirection(lines, ids, 0, 0, 1);
188	
189	  const solidId = ids.next();
190	  lines.push(
191	    `#${solidId}=IFCEXTRUDEDAREASOLID(${ifcRef(profileId)},${ifcRef(extrusionPlacementId)},${ifcRef(extrusionDirId)},${mm2m(heightMm).toFixed(6)});`,
192	  );
193	
194	  // Local placement for the wall (placed at wall start, rotated by wall angle)
195	  const wallOriginId = emitCartesianPoint(lines, ids, 0, 0, 0);
196	  const wallAxisId = emitDirection(lines, ids, 0, 0, 1);
197	  const wallRefDirId = emitDirection(lines, ids, 1, 0, 0);
198	  const wallAxis2PlaceId = emitAxis2Placement3D(lines, ids, wallOriginId, wallAxisId, wallRefDirId);
199	  const placementId = emitLocalPlacement(lines, ids, null, wallAxis2PlaceId);
200	
201	  const shapeRepId = emitShapeRepresentation(lines, ids, contextId, 'Body', 'SweptSolid', [
202	    solidId,
203	  ]);
204	
205	  return { shapeRepId, placementId };
206	}
207	
208	// ---------------------------------------------------------------------------
209	// Bounding-box body for non-wall elements
210	// ---------------------------------------------------------------------------
211	
212	function emitBBoxBody(
213	  lines: Lines,
214	  ids: IdCounter,
215	  contextId: number,
216	  widthMm: number,
217	  depthMm: number,
218	  heightMm: number,
219	  originXm: number,
220	  originYm: number,
221	  originZm: number,
222	): { shapeRepId: number; placementId: number } {
223	  const profileOriginId = emitCartesianPoint(lines, ids, 0, 0);
224	  const profileXDirId = emitDirection(lines, ids, 1, 0);
225	  const profileAxisId = ids.next();
226	  lines.push(
227	    `#${profileAxisId}=IFCAXIS2PLACEMENT2D(${ifcRef(profileOriginId)},${ifcRef(profileXDirId)});`,
228	  );
229	  const profileId = ids.next();
230	  lines.push(
231	    `#${profileId}=IFCRECTANGLEPROFILEDEF(.AREA.,$,${ifcRef(profileAxisId)},${mm2m(widthMm).toFixed(6)},${mm2m(depthMm).toFixed(6)});`,
232	  );
233	
234	  const extrusionOriginId = emitCartesianPoint(lines, ids, 0, 0, 0);
235	  const extrusionAxisId = emitDirection(lines, ids, 0, 0, 1);
236	  const extrusionRefId = emitDirection(lines, ids, 1, 0, 0);
237	  const extrusionPlacementId = emitAxis2Placement3D(
238	    lines,
239	    ids,
240	    extrusionOriginId,
241	    extrusionAxisId,
242	    extrusionRefId,
243	  );
244	  const extrusionDirId = emitDirection(lines, ids, 0, 0, 1);
245	
246	  const solidId = ids.next();
247	  lines.push(
248	    `#${solidId}=IFCEXTRUDEDAREASOLID(${ifcRef(profileId)},${ifcRef(extrusionPlacementId)},${ifcRef(extrusionDirId)},${mm2m(Math.max(heightMm, 1)).toFixed(6)});`,
249	  );
250	
251	  const originId = emitCartesianPoint(lines, ids, originXm, originYm, originZm);
252	  const axisId = emitDirection(lines, ids, 0, 0, 1);
253	  const refDirId = emitDirection(lines, ids, 1, 0, 0);
254	  const axis2PlaceId = emitAxis2Placement3D(lines, ids, originId, axisId, refDirId);
255	  const placementId = emitLocalPlacement(lines, ids, null, axis2PlaceId);
256	
257	  const shapeRepId = emitShapeRepresentation(lines, ids, contextId, 'Body', 'SweptSolid', [
258	    solidId,
259	  ]);
260	
261	  return { shapeRepId, placementId };
262	}
263	
264	// ---------------------------------------------------------------------------
265	// Polygon-based floor/roof body
266	// ---------------------------------------------------------------------------
267	
268	function emitPolyBody(
269	  lines: Lines,
270	  ids: IdCounter,
271	  contextId: number,
272	  boundaryMm: XY[],
273	  thicknessMm: number,
274	  elevationMm: number,
275	): { shapeRepId: number; placementId: number } {
276	  // Build polyline profile
277	  const pointIds = boundaryMm.map((p) => emitCartesianPoint(lines, ids, mm2m(p.xMm), mm2m(p.yMm)));
278	  // close the polyline by repeating first point
279	  pointIds.push(pointIds[0]);
280	  const polylineId = ids.next();
281	  lines.push(`#${polylineId}=IFCPOLYLINE(${ifcRefList(pointIds)});`);
282	  const profileId = ids.next();
283	  lines.push(`#${profileId}=IFCARBITRARYCLOSEDPROFILEDEF(.AREA.,$,${ifcRef(polylineId)});`);
284	
285	  const extrusionOriginId = emitCartesianPoint(lines, ids, 0, 0, 0);
286	  const extrusionAxisId = emitDirection(lines, ids, 0, 0, 1);
287	  const extrusionRefId = emitDirection(lines, ids, 1, 0, 0);
288	  const extrusionPlacementId = emitAxis2Placement3D(
289	    lines,
290	    ids,
291	    extrusionOriginId,
292	    extrusionAxisId,
293	    extrusionRefId,
294	  );
295	  const extrusionDirId = emitDirection(lines, ids, 0, 0, 1);
296	  const solidId = ids.next();
297	  const extrusionDepth = Math.max(thicknessMm, 1);
298	  lines.push(
299	    `#${solidId}=IFCEXTRUDEDAREASOLID(${ifcRef(profileId)},${ifcRef(extrusionPlacementId)},${ifcRef(extrusionDirId)},${mm2m(extrusionDepth).toFixed(6)});`,
300	  );
301	
302	  const originId = emitCartesianPoint(lines, ids, 0, 0, mm2m(elevationMm));
303	  const axisId = emitDirection(lines, ids, 0, 0, 1);
304	  const refDirId = emitDirection(lines, ids, 1, 0, 0);
305	  const axis2PlaceId = emitAxis2Placement3D(lines, ids, originId, axisId, refDirId);
306	  const placementId = emitLocalPlacement(lines, ids, null, axis2PlaceId);
307	
308	  const shapeRepId = emitShapeRepresentation(lines, ids, contextId, 'Body', 'SweptSolid', [
309	    solidId,
310	  ]);
311	  return { shapeRepId, placementId };
312	}
313	
314	// ---------------------------------------------------------------------------
315	// Main exporter
316	// ---------------------------------------------------------------------------
317	
318	export function exportToIfc(
319	  elementsById: Record<string, Element>,
320	  _opts?: IfcExportOptions,
321	): string {
322	  const lines: string[] = [];
323	  const ids = new IdCounter();
324	
325	  const now = new Date().toISOString().replace(/\.\d+Z$/, '');
326	
327	  // -------------------------------------------------------------------------
328	  // HEADER
329	  // -------------------------------------------------------------------------
330	  lines.push('ISO-10303-21;');
331	  lines.push('HEADER;');
332	  lines.push(`FILE_DESCRIPTION(('ViewDefinition [CoordinationView]'),'2;1');`);
333	  lines.push(`FILE_NAME('project.ifc','${now}',(''),(''),'','bim-ai','');`);
334	  lines.push(`FILE_SCHEMA(('IFC2X3'));`);
335	  lines.push('ENDSEC;');
336	  lines.push('DATA;');
337	
338	  const dataLines: string[] = [];
339	
340	  // -------------------------------------------------------------------------
341	  // Shared geometric context
342	  // -------------------------------------------------------------------------
343	  const originId = emitCartesianPoint(dataLines, ids, 0, 0, 0);
344	  const zDirId = emitDirection(dataLines, ids, 0, 0, 1);
345	  const xDirId = emitDirection(dataLines, ids, 1, 0, 0);
346	  const worldPlacementId = emitAxis2Placement3D(dataLines, ids, originId, zDirId, xDirId);
347	
348	  const geoContextId = ids.next();
349	  dataLines.push(
350	    `#${geoContextId}=IFCGEOMETRICREPRESENTATIONCONTEXT($,'Model',3,1.E-05,${ifcRef(worldPlacementId)},$);`,
351	  );
352	
353	  // -------------------------------------------------------------------------
354	  // Units
355	  // -------------------------------------------------------------------------
356	  const lengthUnitId = ids.next();
357	  dataLines.push(`#${lengthUnitId}=IFCSIUNIT(*,.LENGTHUNIT.,$,.METRE.);`);
358	  const areaUnitId = ids.next();
359	  dataLines.push(`#${areaUnitId}=IFCSIUNIT(*,.AREAUNIT.,$,.SQUARE_METRE.);`);
360	  const volumeUnitId = ids.next();
361	  dataLines.push(`#${volumeUnitId}=IFCSIUNIT(*,.VOLUMEUNIT.,$,.CUBIC_METRE.);`);
362	  const unitAssignmentId = ids.next();
363	  dataLines.push(
364	    `#${unitAssignmentId}=IFCUNITASSIGNMENT(${ifcRefList([lengthUnitId, areaUnitId, volumeUnitId])});`,
365	  );
366	
367	  // -------------------------------------------------------------------------
368	  // Project hierarchy: IFCPROJECT → IFCSITE → IFCBUILDING → IFCBUILDINGSTOREY
369	  // -------------------------------------------------------------------------
370	  const projectId = ids.next();
371	  dataLines.push(
372	    `#${projectId}=IFCPROJECT('${guid()}',$,'bim-ai Project',$,$,$,$,${ifcRefList([geoContextId])},${ifcRef(unitAssignmentId)});`,
373	  );
374	
375	  // Site
376	  const siteOriginId = emitCartesianPoint(dataLines, ids, 0, 0, 0);
377	  const siteAxisId = emitDirection(dataLines, ids, 0, 0, 1);
378	  const siteRefId = emitDirection(dataLines, ids, 1, 0, 0);
379	  const sitePlacementAxis = emitAxis2Placement3D(
380	    dataLines,
381	    ids,
382	    siteOriginId,
383	    siteAxisId,
384	    siteRefId,
385	  );
386	  const siteLocalPlaceId = emitLocalPlacement(dataLines, ids, null, sitePlacementAxis);
387	  const siteId = ids.next();
388	  dataLines.push(
389	    `#${siteId}=IFCSITE('${guid()}',$,'Site',$,$,${ifcRef(siteLocalPlaceId)},$,$,.ELEMENT.,$,$,$,$,$);`,
390	  );
391	
392	  // Building
393	  const bldgOriginId = emitCartesianPoint(dataLines, ids, 0, 0, 0);
394	  const bldgAxisId = emitDirection(dataLines, ids, 0, 0, 1);
395	  const bldgRefId = emitDirection(dataLines, ids, 1, 0, 0);
396	  const bldgPlacementAxis = emitAxis2Placement3D(
397	    dataLines,
398	    ids,
399	    bldgOriginId,
400	    bldgAxisId,
401	    bldgRefId,
402	  );
403	  const bldgLocalPlaceId = emitLocalPlacement(dataLines, ids, siteLocalPlaceId, bldgPlacementAxis);
404	  const buildingId = ids.next();
405	  dataLines.push(
406	    `#${buildingId}=IFCBUILDING('${guid()}',$,'Building',$,$,${ifcRef(bldgLocalPlaceId)},$,$,.ELEMENT.,$,$,$);`,
407	  );
408	
409	  // -------------------------------------------------------------------------
410	  // Collect elements by kind
411	  // -------------------------------------------------------------------------
412	  const elements = Object.values(elementsById);
413	
414	  const levels = elements.filter((e) => e.kind === 'level') as Extract<
415	    Element,
416	    { kind: 'level' }
417	  >[];
418	  const walls = elements.filter((e) => e.kind === 'wall') as Extract<Element, { kind: 'wall' }>[];
419	  const doors = elements.filter((e) => e.kind === 'door') as Extract<Element, { kind: 'door' }>[];
420	  const windows = elements.filter((e) => e.kind === 'window') as Extract<
421	    Element,
422	    { kind: 'window' }
423	  >[];
424	  const floors = elements.filter((e) => e.kind === 'floor') as Extract<
425	    Element,
426	    { kind: 'floor' }
427	  >[];
428	  const roofs = elements.filter((e) => e.kind === 'roof') as Extract<Element, { kind: 'roof' }>[];
429	  const rooms = elements.filter((e) => e.kind === 'room') as Extract<Element, { kind: 'room' }>[];
430	
431	  // Map level element id → IFC storey id
432	  const levelIfcId: Record<string, number> = {};
433	  // Map level element id → elevationMm
434	  const levelElevation: Record<string, number> = {};
435	
436	  // -------------------------------------------------------------------------
437	  // IFCBUILDINGSTOREY for each level
438	  // -------------------------------------------------------------------------
439	  const storeyIds: number[] = [];
440	  for (const level of levels) {
441	    levelElevation[level.id] = level.elevationMm;
442	    const elevM = mm2m(level.elevationMm);
443	
444	    const lvlOriginId = emitCartesianPoint(dataLines, ids, 0, 0, elevM);
445	    const lvlAxisId = emitDirection(dataLines, ids, 0, 0, 1);
446	    const lvlRefId = emitDirection(dataLines, ids, 1, 0, 0);
447	    const lvlAxis2PlaceId = emitAxis2Placement3D(dataLines, ids, lvlOriginId, lvlAxisId, lvlRefId);
448	    const lvlLocalPlaceId = emitLocalPlacement(dataLines, ids, bldgLocalPlaceId, lvlAxis2PlaceId);
449	
450	    const storeyId = ids.next();
451	    levelIfcId[level.id] = storeyId;
452	    storeyIds.push(storeyId);
453	    dataLines.push(
454	      `#${storeyId}=IFCBUILDINGSTOREY('${guid()}',$,${ifcStr(level.name)},$,$,${ifcRef(lvlLocalPlaceId)},$,$,.ELEMENT.,${elevM.toFixed(6)});`,
455	    );
456	  }
457	
458	  // -------------------------------------------------------------------------
459	  // Map wall element id → IFC wall id (needed for door/window void references)
460	  // -------------------------------------------------------------------------
461	  const wallIfcId: Record<string, number> = {};
462	  const wallIfcPlaceId: Record<string, number> = {};
463	
464	  // -------------------------------------------------------------------------
465	  // IFCWALLSTANDARDCASE for each wall
466	  // -------------------------------------------------------------------------
467	  const wallProductIds: number[] = [];
468	  for (const wall of walls) {
469	    const lengthMm = wallLength(wall.start, wall.end);
470	    const angleDeg = wallAngleDeg(wall.start, wall.end);
471	    const angleRad = (angleDeg * Math.PI) / 180;
472	    const cosA = Math.cos(angleRad);
473	    const sinA = Math.sin(angleRad);
474	    const elevMm = levelElevation[wall.levelId] ?? 0;
475	
476	    // Profile and extruded solid
477	    const profileOriginId = emitCartesianPoint(dataLines, ids, 0, 0);
478	    const profileXDirId = emitDirection(dataLines, ids, 1, 0);
479	    const profileAxisId = ids.next();
480	    dataLines.push(
481	      `#${profileAxisId}=IFCAXIS2PLACEMENT2D(${ifcRef(profileOriginId)},${ifcRef(profileXDirId)});`,
482	    );
483	    const profileId = ids.next();
484	    dataLines.push(
485	      `#${profileId}=IFCRECTANGLEPROFILEDEF(.AREA.,$,${ifcRef(profileAxisId)},${mm2m(lengthMm).toFixed(6)},${mm2m(wall.thicknessMm).toFixed(6)});`,
486	    );
487	    const extOriginId = emitCartesianPoint(dataLines, ids, 0, 0, 0);
488	    const extAxisId = emitDirection(dataLines, ids, 0, 0, 1);
489	    const extRefId = emitDirection(dataLines, ids, 1, 0, 0);
490	    const extPlaceId = emitAxis2Placement3D(dataLines, ids, extOriginId, extAxisId, extRefId);
491	    const extDirId = emitDirection(dataLines, ids, 0, 0, 1);
492	    const solidId = ids.next();
493	    dataLines.push(
494	      `#${solidId}=IFCEXTRUDEDAREASOLID(${ifcRef(profileId)},${ifcRef(extPlaceId)},${ifcRef(extDirId)},${mm2m(wall.heightMm).toFixed(6)});`,
495	    );
496	
497	    // Wall placement: origin at wall start, rotated by wall angle
498	    const wallOriginId = emitCartesianPoint(
499	      dataLines,
500	      ids,
501	      mm2m(wall.start.xMm),
502	      mm2m(wall.start.yMm),
503	      mm2m(elevMm),
504	    );
505	    const wallAxisId = emitDirection(dataLines, ids, 0, 0, 1);
506	    const wallRefId = emitDirection(dataLines, ids, cosA, sinA, 0);
507	    const wallAxis2PlaceId = emitAxis2Placement3D(
508	      dataLines,
509	      ids,
510	      wallOriginId,
511	      wallAxisId,
512	      wallRefId,
513	    );
514	    const wallLocalPlaceId = emitLocalPlacement(dataLines, ids, null, wallAxis2PlaceId);
515	    wallIfcPlaceId[wall.id] = wallLocalPlaceId;
516	
517	    const shapeRepId = emitShapeRepresentation(dataLines, ids, geoContextId, 'Body', 'SweptSolid', [
518	      solidId,
519	    ]);
520	    const productShapeId = emitProductDefinitionShape(dataLines, ids, [shapeRepId]);
521	
522	    const wallIfcEntityId = ids.next();
523	    wallIfcId[wall.id] = wallIfcEntityId;
524	    wallProductIds.push(wallIfcEntityId);
525	    dataLines.push(
526	      `#${wallIfcEntityId}=IFCWALLSTANDARDCASE('${guid()}',$,${ifcStr(wall.name)},$,$,${ifcRef(wallLocalPlaceId)},${ifcRef(productShapeId)},$);`,
527	    );
528	  }
529	
530	  // -------------------------------------------------------------------------
531	  // IFCDOOR + IFCOPENINGELEMENT + IFCRELVOIDSELEMENT
532	  // -------------------------------------------------------------------------
533	  const doorProductIds: number[] = [];
534	  const openingElementIds: number[] = [];
535	
536	  for (const door of doors) {
537	    const hostWallId = door.wallId;
538	    const hostWall = elementsById[hostWallId] as Extract<Element, { kind: 'wall' }> | undefined;
539	    const elevMm = hostWall ? (levelElevation[hostWall.levelId] ?? 0) : 0;
540	    const widthMm = door.widthMm;
541	    const heightMm = 2100; // default door height (no heightMm on door type)
542	
543	    // Opening element placement
544	    const openOriginId = emitCartesianPoint(dataLines, ids, 0, 0, mm2m(elevMm));
545	    const openAxisId = emitDirection(dataLines, ids, 0, 0, 1);
546	    const openRefId = emitDirection(dataLines, ids, 1, 0, 0);
547	    const openAxis2PlaceId = emitAxis2Placement3D(
548	      dataLines,
549	      ids,
550	      openOriginId,
551	      openAxisId,
552	      openRefId,
553	    );
554	    const openLocalPlaceId = emitLocalPlacement(dataLines, ids, null, openAxis2PlaceId);
555	
556	    // Opening shape (bbox)
557	    const openProfileOriginId = emitCartesianPoint(dataLines, ids, 0, 0);
558	    const openProfileXDirId = emitDirection(dataLines, ids, 1, 0);
559	    const openProfileAxisId = ids.next();
560	    dataLines.push(
561	      `#${openProfileAxisId}=IFCAXIS2PLACEMENT2D(${ifcRef(openProfileOriginId)},${ifcRef(openProfileXDirId)});`,
562	    );
563	    const openProfileId = ids.next();
564	    const hostThicknessMm = hostWall?.thicknessMm ?? 200;
565	    dataLines.push(
566	      `#${openProfileId}=IFCRECTANGLEPROFILEDEF(.AREA.,$,${ifcRef(openProfileAxisId)},${mm2m(widthMm).toFixed(6)},${mm2m(hostThicknessMm).toFixed(6)});`,
567	    );
568	    const openExtOriginId = emitCartesianPoint(dataLines, ids, 0, 0, 0);
569	    const openExtAxisId = emitDirection(dataLines, ids, 0, 0, 1);
570	    const openExtRefId = emitDirection(dataLines, ids, 1, 0, 0);
571	    const openExtPlaceId = emitAxis2Placement3D(
572	      dataLines,
573	      ids,
574	      openExtOriginId,
575	      openExtAxisId,
576	      openExtRefId,
577	    );
578	    const openExtDirId = emitDirection(dataLines, ids, 0, 0, 1);
579	    const openSolidId = ids.next();
580	    dataLines.push(
581	      `#${openSolidId}=IFCEXTRUDEDAREASOLID(${ifcRef(openProfileId)},${ifcRef(openExtPlaceId)},${ifcRef(openExtDirId)},${mm2m(heightMm).toFixed(6)});`,
582	    );
583	    const openShapeRepId = emitShapeRepresentation(
584	      dataLines,
585	      ids,
586	      geoContextId,
587	      'Body',
588	      'SweptSolid',
589	      [openSolidId],
590	    );
591	    const openProductShapeId = emitProductDefinitionShape(dataLines, ids, [openShapeRepId]);
592	
593	    const openingId = ids.next();
594	    openingElementIds.push(openingId);
595	    dataLines.push(
596	      `#${openingId}=IFCOPENINGELEMENT('${guid()}',$,'Opening',$,$,${ifcRef(openLocalPlaceId)},${ifcRef(openProductShapeId)},$);`,
597	    );
598	
599	    // RelVoidsElement (host wall voids)
600	    if (hostWallId && wallIfcId[hostWallId]) {
601	      const relVoidId = ids.next();
602	      dataLines.push(
603	        `#${relVoidId}=IFCRELVOIDSELEMENT('${guid()}',$,$,$,${ifcRef(wallIfcId[hostWallId])},${ifcRef(openingId)});`,
604	      );
605	    }
606	
607	    // Door placement
608	    const doorOriginId = emitCartesianPoint(dataLines, ids, 0, 0, mm2m(elevMm));
609	    const doorAxisId = emitDirection(dataLines, ids, 0, 0, 1);
610	    const doorRefId = emitDirection(dataLines, ids, 1, 0, 0);
611	    const doorAxis2PlaceId = emitAxis2Placement3D(
612	      dataLines,
613	      ids,
614	      doorOriginId,
615	      doorAxisId,
616	      doorRefId,
617	    );
618	    const doorLocalPlaceId = emitLocalPlacement(dataLines, ids, null, doorAxis2PlaceId);
619	
620	    const doorId = ids.next();
621	    doorProductIds.push(doorId);
622	    dataLines.push(
623	      `#${doorId}=IFCDOOR('${guid()}',$,${ifcStr(door.name)},$,$,${ifcRef(doorLocalPlaceId)},$,$,${mm2m(heightMm).toFixed(6)},${mm2m(widthMm).toFixed(6)});`,
624	    );
625	
626	    // RelFillsElement (door fills opening)
627	    const relFillId = ids.next();
628	    dataLines.push(
629	      `#${relFillId}=IFCRELFILLSELEMENT('${guid()}',$,$,$,${ifcRef(openingId)},${ifcRef(doorId)});`,
630	    );
631	  }
632	
633	  // -------------------------------------------------------------------------
634	  // IFCWINDOW + IFCOPENINGELEMENT + IFCRELVOIDSELEMENT
635	  // -------------------------------------------------------------------------
636	  const windowProductIds: number[] = [];
637	
638	  for (const win of windows) {
639	    const hostWallId = win.wallId;
640	    const hostWall = elementsById[hostWallId] as Extract<Element, { kind: 'wall' }> | undefined;
641	    const elevMm = hostWall ? (levelElevation[hostWall.levelId] ?? 0) : 0;
642	    const sillMm = win.sillHeightMm;
643	    const widthMm = win.widthMm;
644	    const heightMm = win.heightMm;
645	
646	    // Opening element
647	    const openOriginId = emitCartesianPoint(dataLines, ids, 0, 0, mm2m(elevMm + sillMm));
648	    const openAxisId = emitDirection(dataLines, ids, 0, 0, 1);
649	    const openRefId = emitDirection(dataLines, ids, 1, 0, 0);
650	    const openAxis2PlaceId = emitAxis2Placement3D(
651	      dataLines,
652	      ids,
653	      openOriginId,
654	      openAxisId,
655	      openRefId,
656	    );
657	    const openLocalPlaceId = emitLocalPlacement(dataLines, ids, null, openAxis2PlaceId);
658	
659	    const openProfileOriginId = emitCartesianPoint(dataLines, ids, 0, 0);
660	    const openProfileXDirId = emitDirection(dataLines, ids, 1, 0);
661	    const openProfileAxisId = ids.next();
662	    dataLines.push(
663	      `#${openProfileAxisId}=IFCAXIS2PLACEMENT2D(${ifcRef(openProfileOriginId)},${ifcRef(openProfileXDirId)});`,
664	    );
665	    const openProfileId = ids.next();
666	    const hostThicknessMm = hostWall?.thicknessMm ?? 200;
667	    dataLines.push(
668	      `#${openProfileId}=IFCRECTANGLEPROFILEDEF(.AREA.,$,${ifcRef(openProfileAxisId)},${mm2m(widthMm).toFixed(6)},${mm2m(hostThicknessMm).toFixed(6)});`,
669	    );
670	    const openExtOriginId = emitCartesianPoint(dataLines, ids, 0, 0, 0);
671	    const openExtAxisId = emitDirection(dataLines, ids, 0, 0, 1);
672	    const openExtRefId = emitDirection(dataLines, ids, 1, 0, 0);
673	    const openExtPlaceId = emitAxis2Placement3D(
674	      dataLines,
675	      ids,
676	      openExtOriginId,
677	      openExtAxisId,
678	      openExtRefId,
679	    );
680	    const openExtDirId = emitDirection(dataLines, ids, 0, 0, 1);
681	    const openSolidId = ids.next();
682	    dataLines.push(
683	      `#${openSolidId}=IFCEXTRUDEDAREASOLID(${ifcRef(openProfileId)},${ifcRef(openExtPlaceId)},${ifcRef(openExtDirId)},${mm2m(heightMm).toFixed(6)});`,
684	    );
685	    const openShapeRepId = emitShapeRepresentation(
686	      dataLines,
687	      ids,
688	      geoContextId,
689	      'Body',
690	      'SweptSolid',
691	      [openSolidId],
692	    );
693	    const openProductShapeId = emitProductDefinitionShape(dataLines, ids, [openShapeRepId]);
694	
695	    const openingId = ids.next();
696	    openingElementIds.push(openingId);
697	    dataLines.push(
698	      `#${openingId}=IFCOPENINGELEMENT('${guid()}',$,'Opening',$,$,${ifcRef(openLocalPlaceId)},${ifcRef(openProductShapeId)},$);`,
699	    );
700	
701	    if (hostWallId && wallIfcId[hostWallId]) {
702	      const relVoidId = ids.next();
703	      dataLines.push(
704	        `#${relVoidId}=IFCRELVOIDSELEMENT('${guid()}',$,$,$,${ifcRef(wallIfcId[hostWallId])},${ifcRef(openingId)});`,
705	      );
706	    }
707	
708	    // Window placement
709	    const winOriginId = emitCartesianPoint(dataLines, ids, 0, 0, mm2m(elevMm + sillMm));
710	    const winAxisId = emitDirection(dataLines, ids, 0, 0, 1);
711	    const winRefId = emitDirection(dataLines, ids, 1, 0, 0);
712	    const winAxis2PlaceId = emitAxis2Placement3D(dataLines, ids, winOriginId, winAxisId, winRefId);
713	    const winLocalPlaceId = emitLocalPlacement(dataLines, ids, null, winAxis2PlaceId);
714	
715	    const windowId = ids.next();
716	    windowProductIds.push(windowId);
717	    dataLines.push(
718	      `#${windowId}=IFCWINDOW('${guid()}',$,${ifcStr(win.name)},$,$,${ifcRef(winLocalPlaceId)},$,$,${mm2m(heightMm).toFixed(6)},${mm2m(widthMm).toFixed(6)});`,
719	    );
720	
721	    const relFillId = ids.next();
722	    dataLines.push(
723	      `#${relFillId}=IFCRELFILLSELEMENT('${guid()}',$,$,$,${ifcRef(openingId)},${ifcRef(windowId)});`,
724	    );
725	  }
726	
727	  // -------------------------------------------------------------------------
728	  // IFCSLAB (floor)
729	  // -------------------------------------------------------------------------
730	  const floorSlabIds: number[] = [];
731	  for (const floor of floors) {
732	    const elevMm = levelElevation[floor.levelId] ?? 0;
733	    const { shapeRepId, placementId } = emitPolyBody(
734	      dataLines,
735	      ids,
736	      geoContextId,
737	      floor.boundaryMm,
738	      floor.thicknessMm,
739	      elevMm,
740	    );
741	    const productShapeId = emitProductDefinitionShape(dataLines, ids, [shapeRepId]);
742	    const slabId = ids.next();
743	    floorSlabIds.push(slabId);
744	    dataLines.push(
745	      `#${slabId}=IFCSLAB('${guid()}',$,${ifcStr(floor.name)},$,$,${ifcRef(placementId)},${ifcRef(productShapeId)},$,.FLOOR.);`,
746	    );
747	  }
748	
749	  // -------------------------------------------------------------------------
750	  // IFCSLAB (roof)
751	  // -------------------------------------------------------------------------
752	  const roofSlabIds: number[] = [];
753	  for (const roof of roofs) {
754	    const footprint = roof.footprintMm ?? [];
755	    const elevMm = levelElevation[roof.referenceLevelId] ?? 0;
756	    const thicknessMm = 300; // default
757	
758	    if (footprint.length >= 3) {
759	      const { shapeRepId, placementId } = emitPolyBody(
760	        dataLines,
761	        ids,
762	        geoContextId,
763	        footprint,
764	        thicknessMm,
765	        elevMm,
766	      );
767	      const productShapeId = emitProductDefinitionShape(dataLines, ids, [shapeRepId]);
768	      const slabId = ids.next();
769	      roofSlabIds.push(slabId);
770	      dataLines.push(
771	        `#${slabId}=IFCSLAB('${guid()}',$,${ifcStr(roof.name)},$,$,${ifcRef(placementId)},${ifcRef(productShapeId)},$,.ROOF.);`,
772	      );
773	    } else {
774	      // No footprint geometry; emit a minimal placement
775	      const placeholderOriginId = emitCartesianPoint(dataLines, ids, 0, 0, mm2m(elevMm));
776	      const placeholderAxisId = emitDirection(dataLines, ids, 0, 0, 1);
777	      const placeholderRefId = emitDirection(dataLines, ids, 1, 0, 0);
778	      const placeholderAxis2PlaceId = emitAxis2Placement3D(
779	        dataLines,
780	        ids,
781	        placeholderOriginId,
782	        placeholderAxisId,
783	        placeholderRefId,
784	      );
785	      const placeholderPlaceId = emitLocalPlacement(dataLines, ids, null, placeholderAxis2PlaceId);
786	      const slabId = ids.next();
787	      roofSlabIds.push(slabId);
788	      dataLines.push(
789	        `#${slabId}=IFCSLAB('${guid()}',$,${ifcStr(roof.name)},$,$,${ifcRef(placeholderPlaceId)},$,$,.ROOF.);`,
790	      );
791	    }
792	  }
793	
794	  // -------------------------------------------------------------------------
795	  // IFCSPACE (room)
796	  // -------------------------------------------------------------------------
797	  const spaceIds: number[] = [];
798	  for (const room of rooms) {
799	    const elevMm = levelElevation[room.levelId] ?? 0;
800	    const outline = room.outlineMm ?? [];
801	    const thicknessMm = 2800; // default room height
802	
803	    if (outline.length >= 3) {
804	      const { shapeRepId, placementId } = emitPolyBody(
805	        dataLines,
806	        ids,
807	        geoContextId,
808	        outline,
809	        thicknessMm,
810	        elevMm,
811	      );
812	      const productShapeId = emitProductDefinitionShape(dataLines, ids, [shapeRepId]);
813	      const spaceId = ids.next();
814	      spaceIds.push(spaceId);
815	      dataLines.push(
816	        `#${spaceId}=IFCSPACE('${guid()}',$,${ifcStr(room.name)},$,$,${ifcRef(placementId)},${ifcRef(productShapeId)},$,.ELEMENT.,$);`,
817	      );
818	    } else {
819	      const spaceOriginId = emitCartesianPoint(dataLines, ids, 0, 0, mm2m(elevMm));
820	      const spaceAxisId = emitDirection(dataLines, ids, 0, 0, 1);
821	      const spaceRefId = emitDirection(dataLines, ids, 1, 0, 0);
822	      const spaceAxis2PlaceId = emitAxis2Placement3D(
823	        dataLines,
824	        ids,
825	        spaceOriginId,
826	        spaceAxisId,
827	        spaceRefId,
828	      );
829	      const spaceLocalPlaceId = emitLocalPlacement(dataLines, ids, null, spaceAxis2PlaceId);
830	      const spaceId = ids.next();
831	      spaceIds.push(spaceId);
832	      dataLines.push(
833	        `#${spaceId}=IFCSPACE('${guid()}',$,${ifcStr(room.name)},$,$,${ifcRef(spaceLocalPlaceId)},$,$,.ELEMENT.,$);`,
834	      );
835	    }
836	  }
837	
838	  // -------------------------------------------------------------------------
839	  // Spatial structure relationships
840	  // -------------------------------------------------------------------------
841	
842	  // Project → Site
843	  const relProjectSiteId = ids.next();
844	  dataLines.push(
845	    `#${relProjectSiteId}=IFCRELAGGREGATES('${guid()}',$,$,$,${ifcRef(projectId)},${ifcRefList([siteId])});`,
846	  );
847	
848	  // Site → Building
849	  const relSiteBuildingId = ids.next();
850	  dataLines.push(
851	    `#${relSiteBuildingId}=IFCRELAGGREGATES('${guid()}',$,$,$,${ifcRef(siteId)},${ifcRefList([buildingId])});`,
852	  );
853	
854	  // Building → Storeys
855	  if (storeyIds.length > 0) {
856	    const relBuildingStoreysId = ids.next();
857	    dataLines.push(
858	      `#${relBuildingStoreysId}=IFCRELAGGREGATES('${guid()}',$,$,$,${ifcRef(buildingId)},${ifcRefList(storeyIds)});`,
859	    );
860	  }
861	
862	  // Contained elements in building (walls, doors, windows, slabs, spaces)
863	  const allProductIds = [
864	    ...wallProductIds,
865	    ...doorProductIds,
866	    ...windowProductIds,
867	    ...floorSlabIds,
868	    ...roofSlabIds,
869	    ...spaceIds,
870	  ];
871	  if (allProductIds.length > 0) {
